#!/usr/bin/env node
import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';

const ROOT = process.cwd();
const OUT = path.join(ROOT, 'artifacts', 'browser-beta-demo');
fs.rmSync(OUT, { recursive: true, force: true });
fs.mkdirSync(OUT, { recursive: true });
const now = new Date().toISOString();
const scenario = process.env.GOALOS_DEMO_SCENARIO || process.argv[2] || 'AI research report';
function write(name, value){ fs.writeFileSync(path.join(OUT,name), typeof value === 'string' ? value : JSON.stringify(value,null,2)); }
const base = { scenario, generatedAt: now, mode:'public-safe synthetic demo', dataCaptured:'none', valueMoved:0, publicSiteRule:'No forms, no uploads, no cookies, no analytics, no wallets, no payments, no personal or confidential data.' };
write('mission-contract.json', { ...base, objective:`Synthetic proof-to-acceptance run for ${scenario}`, successCriteria:['criteria mapped','evidence docket emitted','receipt sealed'], failureCriteria:['unsupported claim','missing evidence','boundary violation'] });
write('claims-matrix.json', { ...base, claims:[{claim:'The deliverable is review-ready',evidence:'synthetic artifacts mapped to criteria',status:'demo-supported'},{claim:'The receipt is replayable',evidence:'synthetic receipt id and hash',status:'demo-supported'}] });
write('evidence-docket.json', { ...base, manifest:'GOALOS-BROWSER-BETA-DEMO', publicPrivateBoundary:'public-safe synthetic only', proofPackets:['trace-root-demo','output-hash-demo','policy-root-demo'], replayPath:'browser-local visual replay' });
write('verifier-report.json', { ...base, checks:['criteria linked','risk ledger present','human gate visible','receipt sealed'], verdict:'demo-pass' });
write('risk-ledger.json', { ...base, risks:['unsupported claims stop at gate','no user submissions accepted','no value moved'], controls:['browser-local only','no forms','no uploads','no wallets'] });
const receipt = { ...base, receiptId:'GOALOS-DEMO-RECEIPT-001', decisionState:'review-ready', synthetic:true };
receipt.receiptHash = crypto.createHash('sha256').update(JSON.stringify(receipt)).digest('hex');
write('mission-receipt.json', receipt);
write('README.md', `# GoalOS Browser Beta Demo Bundle\n\nScenario: ${scenario}\n\nThis is a public-safe synthetic demo bundle generated by GitHub Actions. It contains no user data, no confidential data, no wallet action, and no value movement.\n\nFiles:\n\n- mission-contract.json\n- claims-matrix.json\n- evidence-docket.json\n- verifier-report.json\n- risk-ledger.json\n- mission-receipt.json\n`);
console.log(`Browser beta demo bundle generated at ${OUT}`);
